package com.evolua.emotional.application; import com.evolua.emotional.domain.CheckIn; import com.evolua.emotional.domain.CheckInRepository; import java.time.Instant; import java.util.List; import org.springframework.stereotype.Service; @Service public class CheckInService { private final CheckInRepository repository; public CheckInService(CheckInRepository repository) { this.repository = repository; } public CheckIn create(String userId, String mood, String reflection, Integer energyLevel, String recommendedPractice) { return repository.save(new CheckIn(null, userId, mood, reflection, energyLevel, recommendedPractice, Instant.now())); } public List<CheckIn> list(String userId) { return repository.findAllByUserId(userId); } }
